\\[6pt]
\mathrm{M} &\equiv \beta_{0,\,M} + a \cdot \mathrm{X} \\
\mu_{Y} &= \beta_{0,\,Y} + b \cdot \mathrm{M} + c \cdot \mathrm{X} \\
\mathrm{Y} &\sim \text{Normal}(\mu_{Y},\, \sigma_{Y}) \\
\mu_{M_obs} &= 1 \cdot \mathrm{M} \\
\mathrm{M_obs} &\sim \text{Normal}(\mu_{M_obs},\, \sigma_{M_obs}) \\
indirect &\equiv a \cdot b \\
total &\equiv a \cdot b + c
\end{aligned}
